#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream from buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    NetworkPacket packet;

    // Read packet_id using operator>>
    stream >> packet.packet_id;

    // Read username using prefixed adaptor
    stream >> packet.username;

    // Read scores vector using read_container
    // First read the count, then use read_container to read the vector elements
    uint32_t score_count;
    stream >> score_count;
    stream.read_container(packet.scores, score_count);

    // Read metadata string as null-terminated for zero-copy
    stream >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    auto remaining_bytes = adaptor.size() - stream.total_read();
    if (remaining_bytes > 0) {
        stream.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream from buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    PacketInfo info;

    // Use span() for packet_id (first 4 bytes)
    auto id_span = stream.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get a string_view
    std::string_view username_sv;
    stream >> hexi::prefixed(username_sv);
    info.username = username_sv;

    // Skip the scores vector without reading its elements
    // Read the count, then skip the data
    uint32_t score_count;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
