std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor object from the source_buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>> ba(source_buffer);

    // Check if the requested bytes_to_read is available in the buffer
    if (ba.size() < bytes_to_read) {
        throw std::runtime_error("Insufficient data in buffer");
    }

    // Use the read() method to copy data from the buffer_adaptor to the destination vector
    std::vector<uint8_t> destination(bytes_to_read);
    ba.read(destination.data(), bytes_to_read);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a buffer_adaptor object from the dest_buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> ba(dest_buffer);

    // Check if there is enough space in the buffer to write the source_data
    if (ba.free() < source_data.size()) {
        throw std::runtime_error("Insufficient space in buffer");
    }

    // Use the write() method to copy the data from source_data to the buffer
    ba.write(source_data.data(), source_data.size());
