#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create a buffer_adaptor for the provided buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Check available space using the buffer_adaptor's size() method
    auto available_space = adaptor.size();

    // Calculate total data size needed (header + items)
    auto total_size_needed = sizeof(header) + (items.size() * sizeof(uint32_t));

    // If sufficient space exists, write the header and items using binary_stream
    if (available_space >= total_size_needed) {
        // Write the header
        stream << header;

        // Write the items using write_container (automatically handled by operator<< for iterable containers)
        stream << items;

        return true;  // Write successful
    }

    return false;  // Insufficient space
}
```

