#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance
    hexi::block_allocator<int, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Element count: " << element_count << "\n\n";

    // Demonstrate initial state
    std::cout << "1. Initial state: Free list contains " << element_count 
              << " preallocated blocks\n";

    // Demonstrate allocation (calls pop() internally)
    std::cout << "\n2. Allocation operation (calls pop()):\n";
    int* allocated_obj = allocator.allocate();
    std::cout << "   - Allocated one object from free list\n";
    std::cout << "   - Free list size decreased by 1\n";

    // Demonstrate deallocation (calls push() internally)
    std::cout << "\n3. Deallocation operation (calls push()):\n";
    allocator.deallocate(allocated_obj);
    std::cout << "   - Deallocated object back to free list\n";
    std::cout << "   - Free list size increased by 1\n";

    // Demonstrate multiple allocations/deallocations
    std::cout << "\n4. Multiple operations demonstration:\n";
    std::vector<int*> objects;

    // Allocate all available blocks
    for(size_t i = 0; i < element_count; ++i) {
        objects.push_back(allocator.allocate());
        std::cout << "   - Allocated object " << (i+1) << ", free list size: " 
                  << (element_count - i - 1) << "\n";
    }

    // Deallocate all blocks
    for(size_t i = 0; i < element_count; ++i) {
        allocator.deallocate(objects[i]);
        std::cout << "   - Deallocated object " << (i+1) << ", free list size: " 
                  << (element_count - i) << "\n";
    }

    // Demonstrate the circular linked list structure
    std::cout << "\n5. Free list structure demonstration:\n";
    std::cout << "   - The free list is a circular linked list where:\n";
    std::cout << "     * head_ points to the most recently deallocated block\n";
    std::cout << "     * Each block contains a pointer to the next block\n";
    std::cout << "     * When empty, head_ points to itself (sentinel node)\n";

    // Final state
    std::cout << "\n6. Final state: Free list contains " << element_count 
              << " blocks, ready for allocation\n";
}

// Example usage
int main() {
    demonstrate_block_allocator_behavior<5>();
    return 0;
}

