#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    // For compile-time known endianness, use hexi::endian::convert with template parameters
    return hexi::endian::convert<from, to>(value);
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    // For runtime endianness conversion, use storage_in and storage_out with appropriate endian adaptors
    // First convert from input endianness to native, then from native to target endianness
    auto native_value = hexi::endian::storage_out<hexi::endian::as_native_t>(value, from);
    return hexi::endian::storage_in<hexi::endian::as_native_t>(native_value, to);
}
```

## Explanation:

### First Function (`convert_endianness`):
- Uses the template version of `hexi::endian::convert` with compile-time `from` and `to` parameters
- The template parameters `from` and `to` are passed directly to the `convert` function
- This leverages the compile-time optimization where the endianness conversion is determined at compile time

### Second Function (`convert_endianness_runtime`):
- Uses `hexi::endian::storage_out` to convert from the input endianness to native endianness
- Uses `hexi::endian::storage_in` to convert from native endianness to the target endianness
- The `as_native_t` adaptor is used as it represents the native endianness of the system
- This approach handles runtime endianness determination correctly

Both implementations follow the Hexi library conventions and properly handle the endianness conversion as specified in the assessment objectives.

