void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save the current write position using tell_write()
    auto current_pos = buffer.tell_write();

    // Write a placeholder for the header (4 bytes)
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(placeholder));

    // Write the body (example: 10 bytes of zeros)
    std::vector<std::byte> body(10, std::byte{0});
    buffer.write(body.data(), body.size());

    // Seek back to the beginning using absolute seek
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Write the actual header value
    buffer.write(&header_value, sizeof(header_value));

    // Restore the original write position
    buffer.write_seek(hexi::buffer_seek::sk_absolute, current_pos);
}
